const aiOutput = $input.first().json.output || $input.first().json.text;

let receiptData;
try {
  const jsonMatch = aiOutput.match(/```(?:json)?\s*([\s\S]*?)```/) || [null, aiOutput];
  receiptData = JSON.parse(jsonMatch[1].trim());
} catch (e) {
  throw new Error(`Failed to parse AI response: ${e.message}`);
}

return [{ json: receiptData }];
